Default LLM judge prompt (customisable):
You are an expert evaluator. Score the following response on a scale of 1 to 5.

Task: {{input}}
Response: {{output}}
Expected behaviour: {{criteria}}

Criteria:
- 5: Fully addresses the task, accurate, appropriate tone
- 3: Partially addresses the task with minor issues
- 1: Off-topic, inaccurate, or inappropriate

Respond with only a JSON object: {"score": <number>, "reason": "<one sentence>"}

[
  {
    "input": "Summarize this article:\n\nParis is the capital of France...",
    "expected": "Paris is the capital of France.",
    "criteria": "One sentence, factual, no opinions"
  },
  {
    "input": "What is 12 * 8?",
    "expected": "96",
    "criteria": "Exact numeric answer"
  }
]

# Local script to compare two Console CSV exports
import csv

def load_scores(path: str) -> dict:
    with open(path) as f:
        return {row['input'][:60]: float(row.get('score', 0)) for row in csv.DictReader(f)}

def diff_runs(before_path: str, after_path: str) -> None:
    before = load_scores(before_path)
    after  = load_scores(after_path)
    regressions  = [(k, before[k], after[k]) for k in before if k in after and after[k] < before[k] - 0.5]
    improvements = [(k, before[k], after[k]) for k in before if k in after and after[k] > before[k] + 0.5]

    print(f'Regressions ({len(regressions)}):')
    for k, b, a in sorted(regressions, key=lambda x: x[2]-x[1]):
        print(f'  [{b:.1f} -> {a:.1f}] {k}')
    print(f'Improvements ({len(improvements)}):')
    for k, b, a in sorted(improvements, key=lambda x: x[1]-x[2]):
        print(f'  [{b:.1f} -> {a:.1f}] {k}')
